import React, { useState, useEffect } from 'react';
import '../assets/styles/Zoom.css';
import axios from 'axios';

const Zoom = () => {
  const [userInfo, setUserInfo] = useState(null);
  const [error, setError] = useState('');
  const [authenticated, setAuthenticated] = useState(null);
  const [backendUrl, setBackendUrl] = useState('');
  const [accessToken, setAccessToken] = useState('');

  const fetchBackendUrl = async () => {
    try {
      const response = await axios.get('/api/server-info');
      const { ip, port } = response.data;
      const url = `http://${ip}:${port}`;
      setBackendUrl(url);
    } catch (error) {
      console.error('Error fetching backend URL:', error);
    }
  };

  const checkAuthentication = () => {
    const savedToken = localStorage.getItem('zoom_access_token');
    
    if (savedToken) {
      setAccessToken(savedToken);
      setAuthenticated(true);
      fetchUserInfo(); 
    } else {
      axios.get(`${backendUrl}/shortcuts/zoom/check-auth/`)
        .then(response => {
          const data = response.data;
          if (data.authenticated) {
            setAuthenticated(true);
            setAccessToken(data.access_token);
            localStorage.setItem('zoom_access_token', data.access_token);
            fetchUserInfo();
          } else {
            setAuthenticated(false);
          }
        })
        .catch(err => {
          console.error('Error:', err);
          setAuthenticated(false);
        });
    }
  };

  const fetchUserInfo = () => {
    axios.get(`${backendUrl}/shortcuts/zoom/get-contacts/`)
      .then(response => {
        const data = response.data;
        console.log("Response from backend:", data);
        
        if (data.success) {
          if (Array.isArray(data.contacts)) {
            setUserInfo(data.contacts); 
          } else {
            setError('Expected an array of contacts, but received something else.');
          }
        } else {
          setError(data.error || 'Unable to fetch user info');
        }
      })
      .catch(err => {
        setError('An error occurred while fetching user info');
        console.error('Error:', err);
      });
  };

  useEffect(() => {
    fetchBackendUrl(); // Fetch the backend URL first
  }, []);

  useEffect(() => {
    if (backendUrl) {
      checkAuthentication();
    }
  }, [backendUrl]);

  const handleLogin = () => {
    window.location.href = `${backendUrl}/shortcuts/zoom/oauth/login/`;
  };

  const handleLogout = () => {
    localStorage.removeItem('zoom_access_token');
    setAuthenticated(false);
    setAccessToken('');
  };

  return (
    <div className="zoom-container">
      <h1 className="title">Zoom</h1>

      {!authenticated ? (
        <button onClick={handleLogin} className="button login-button">
          Autentificare cu Zoom
        </button>
      ) : (
        <>
          {accessToken && (
            <div className="token-display">
              <p><strong>Access Token:</strong> {accessToken}</p>
            </div>
          )}

          {error && <p className="error">{error}</p>}
          {userInfo ? (
            <ul className="user-info-list">
              {userInfo.map((contact, index) => (
                <li key={index}>
                  <strong>Nume:</strong> {contact.first_name} {contact.last_name}<br />
                  <strong>Email:</strong> {contact.email}<br />
                  <strong>Status:</strong> {contact.status}
                </li>
              ))}
            </ul>
          ) : (
            <p>No contacts found.</p>
          )}

          <button onClick={handleLogout} className="button logout-button">
            Logout
          </button>
        </>
      )}
    </div>
  );
};

export default Zoom;
